   452→    self.toCsv = function (/** @type {any[]} */ dataFields) {
   453→        var sep = ",";
   454→        if (dataFields && !Array.isArray(dataFields)) dataFields = [dataFields];
   455→
   456→        var nodes = self.data.nodes.get();
   457→        var edges = self.data.edges.get();
   458→        var nodesMap = {};
   459→        var csvStr = "";
   460→
   461→        /**
   462→         * @param {{ id: string; label: string; data: { [x: string]: string; }; }} node
   463→         */
   464→        function getNodeStr(node) {
   465→            if (node) var str = node.id + sep + node.label;
   466→            if (dataFields && node.data) {
   467→                sep +
   468→                    dataFields.forEach(function (/** @type {string | number} */ field) {
   469→                        str += node.data[field];
   470→                    });
   471→            }
   472→
   473→            return str;
   474→        }
   475→
   476→        nodes.forEach(function (/** @type {{ id: string | number; }} */ node) {
   477→            nodesMap[node.id] = node;
   478→            if (edges.length == 0) {
   479→                csvStr += getNodeStr(node) + "\n";
   480→            }
   481→        });
   482→        edges.sort(function (/** @type {{ from: number; }} */ a, /** @type {{ from: number; }} */ b) {
   483→            if (a.from > b.from) return 1;
   484→            if (a.from < b.from) return -1;
   485→            return 0;
   486→        });
   487→        edges.forEach(function (/** @type {{ label: string; from: string | number; to: string | number; }} */ edge) {
   488→            var edgeLabel = "->";
   489→            if (edge.label) edgeLabel = edge.label;
   490→            csvStr += getNodeStr(nodesMap[edge.from]) + sep + edgeLabel + sep + getNodeStr(nodesMap[edge.to]) + "\n";
   491→        });
   492→
   493→        return csvStr;
   494→    };
   495→    self.getNodeDescendantIds = function (/** @type {any[]} */ nodeIds, /** @type {any} */ includeParents) {
   496→        if (!Array.isArray(nodeIds)) nodeIds = [nodeIds];
   497→        var nodes = [];
   498→        if (includeParents) nodes = nodeIds;
   499→        var allEdges = self.data.edges.get();
   500→        var allNodes = {};
   501→
   502→        /**
   503→         * @param {any} nodeId
   504→         */
   505→        function recurse(nodeId) {
   506→            allEdges.forEach(function (/** @type {{ from: any; to: string | number; }} */ edge) {
   507→                if (edge.from == nodeId) {
   508→                    if (!allNodes[edge.to]) {
   509→                        allNodes[edge.to] = 1;
   510→                        nodes.push(edge.to);
   511→                        recurse(edge.to);
   512→                    }
   513→                }
   514→                /* if(includeParents && edge.to == nodeId){
   515→             nodes.push(edge.from)
   516→             recurse(edge.from)
   517→         }*/
   518→            });
   519→        }
   520→
   521→        nodeIds.forEach(function (/** @type {any} */ parentId) {
   522→            recurse(parentId);
   523→        });
   524→        return nodes;
   525→    };
