   547→    self.processClicks = function (
   548→        /** @type {{ edges: string | any[]; nodes: string | any[]; event: { srcEvent: { ctrlKey: any; altKey: any; shiftKey: any; }; }; pointer: { DOM: any; }; }} */ params,
   549→        /** @type {{ fixedLayout: any; onclickFn: (arg0: null, arg1: any, arg2: { dbleClick?: any; ctrlKey?: number; altKey?: number; shiftKey?: number; }) => void; onClusterClickFn: (arg0: any, arg1: any, arg2: { dbleClick: any; ctrlKey: number; altKey: number; shiftKey: number; }) => any; }} */ _options,
   550→        /** @type {any} */ isDbleClick,
   551→    ) {
   552→        var now = new Date();
   553→        if (now - lastClickTime < dbleClickIntervalDuration) {
   554→            lastClickTime = now;
   555→            return;
   556→        }
   557→
   558→        if (params.edges.length == 0 && params.nodes.length == 0) {
   559→            //simple click stop animation
   560→
   561→            if (self.simulationOn || _options.fixedLayout) self.network.stopSimulation();
   562→            else {
   563→                self.network.startSimulation();
   564→            }
   565→            self.simulationOn = !self.simulationOn;
   566→            // graphController.hideNodePopover();
   567→            if (_options.onclickFn) _options.onclickFn(null, point, {});
   568→        }
   569→
   570→        // select node
   571→        else if (params.nodes.length == 1) {
   572→            const options = {
   573→                dbleClick: isDbleClick,
   574→                ctrlKey: params.event.srcEvent.ctrlKey ? 1 : 0,
   575→                altKey: params.event.srcEvent.altKey ? 1 : 0,
   576→                shiftKey: params.event.srcEvent.shiftKey ? 1 : 0,
   577→            };
   578→            var point = params.pointer.DOM;
   579→            var nodeId = params.nodes[0];
   580→            var node = self.data.nodes.get(nodeId);
   581→            if (!node && self.network.isCluster(nodeId)) {
   582→                if (_options.onClusterClickFn) return _options.onClusterClickFn(nodeId, point, options);
   583→            }
   584→
   585→            node._graphPosition = params.pointer.DOM;
   586→
   587→            self.context.currentNode = node;
   588→
   589→            if (_options.onclickFn) _options.onclickFn(node, point, options);
   590→        }
   591→
   592→        //select edge{
   593→        else if (params.edges.length == 1) {
   594→            var edgeId = params.edges[0];
   595→            var edge = self.data.edges.get(edgeId);
   596→            edge.fromNode = self.data.nodes.get(edge.from);
   597→            edge.toNode = self.data.nodes.get(edge.to);
   598→            const point = params.pointer.DOM;
   599→            const options = {
   600→                dbleClick: isDbleClick,
   601→                ctrlKey: params.event.srcEvent.ctrlKey ? 1 : 0,
   602→                altKey: params.event.srcEvent.altKey ? 1 : 0,
   603→                shiftKey: params.event.srcEvent.shiftKey ? 1 : 0,
   604→            };
   605→            if (_options.onclickFn) _options.onclickFn(edge, point, options);
   606→        }
