   749→        /** @type {any} */ raw,
   750→    ) {
   751→        if (!self.currentContext) return;
   752→        var positions = self.network.getPositions();
   753→
   754→        if (!raw) {
   755→            for (var key in self.currentContext.options) {
   756→                if (key.indexOf("Fn") > 0) {
   757→                    self.currentContext.options[key] = self.currentContext.options[key].toString();
   758→                }
   759→            }
   760→        }
   761→        var data = {
   762→            nodes: visjsGraph.data.nodes.get(),
   763→            edges: visjsGraph.data.edges.get(),
   764→            context: self.currentContext,
   765→            positions: positions,
   766→        };
   767→        if (!fileName) fileName = prompt("graph name");
