   793→
   794→    self.loadGraph = function (
   795→        /** @type {string | number | string[] | undefined} */ fileName,
   796→        /** @type {any} */ add,
   797→        /** @type {(arg0: null, arg1: { nodes: never[]; edges: never[]; }) => void} */ callback,
   798→    ) {
