   809→                var data = JSON.parse(result);
   810→                var positions = data.positions;
   811→                var options = data.context.options;
   812→                var visjsData = { nodes: [], edges: [] };
   813→                var existingNodes = {};
   814→                if (addToCurrentGraph) existingNodes = self.getExistingIdsMap();
   815→                data.nodes.forEach(function (/** @type {{ id: string | number; fixed: { x: boolean; y: boolean; }; x: any; y: any; }} */ node) {
   816→                    if (!existingNodes[node.id]) {
   817→                        existingNodes[node.id] = 1;
   818→                        if ((node.fixed && positions[node.id]) || options.nodes.fixed) {
   819→                            node.x = positions[node.id].x;
   820→                            node.y = positions[node.id].y;
   821→                            node.fixed = { x: true, y: true };
   822→                        }
   823→                        visjsData.nodes.push(node);
   824→                    }
