   830→                        visjsData.edges.push(edge);
   831→                    }
   832→                });
   833→
   834→                if (callback) return callback(null, visjsData);
   835→
   836→                if (add || (addToCurrentGraph && self.data.nodes && self.data.nodes.getIds().length > 0)) {
   837→                    self.data.nodes.add(visjsData.nodes);
